// Vanilla C11PacketEnchantItem definition:
package net.minecraft.network.play.client;

import net.minecraft.network.Packet;
import net.minecraft.network.PacketBuffer;
import net.minecraft.network.play.INetHandlerPlayServer;
import java.io.IOException;

public class C11PacketEnchantItem implements Packet<INetHandlerPlayServer> {
    private int windowId;
    private int button;

    public C11PacketEnchantItem() {}
    public C11PacketEnchantItem(int windowIdIn, int buttonIn) {
        this.windowId = windowIdIn;
        this.button = buttonIn;
    }

    public void readPacketData(PacketBuffer buf) throws IOException {
        this.windowId = buf.readByte();
        this.button = buf.readByte();
    }

    public void writePacketData(PacketBuffer buf) throws IOException {
        buf.writeByte(this.windowId);
        buf.writeByte(this.button);
    }

    public void processPacket(INetHandlerPlayServer handler) {
        handler.processEnchantItem(this);
    }

    public int getWindowId() { return this.windowId; }
    public int getButton() { return this.button; }
}

